
.signaling-server {
	display: flex;
	flex-wrap: wrap;
	align-items: center;
	gap: var(--default-grid-baseline);
	margin-bottom: 10px;

	& &__textfield {
		width: 300px;
		flex-shrink: 0;
	}

	&__checkbox {
		margin: 0 18px;
	}
}

.test-connection {
	flex-basis: fit-content;
	display: inline-flex;
	align-items: center;
	gap: var(--default-grid-baseline);
}

.test-connection-data {
	flex-basis: 100%;
	display: inline-grid;
	grid-template-columns: auto auto;
	gap: var(--default-grid-baseline);

	&__item {
		display: contents;
	}

	&__caption {
		font-weight: bold;
		margin-inline-end: var(--default-grid-baseline);
	}
}
